package Assignment2;

public class PrintOneToTen {
	
	//Creating method print
	public void  print() {
		for(int i=1; i<=10;i++) {
			System.out.print(" "+i+" ");
		}
		
	}
	//main method
	public static void main(String[] args) {
		//Creating an object p
		PrintOneToTen p= new PrintOneToTen();
		p.print();//Method calling statement
		// TODO Auto-generated method stub
		

	}

}
